'use strict';

/* ── Nav scroll state ─────────────────────────────────────── */
(function initHeader() {
  const header    = document.getElementById('site-header');
  const hamburger = document.querySelector('.header__hamburger');
  const mobileMenu= document.getElementById('mobile-menu');
  const overlay   = document.getElementById('mobile-overlay');
  const closeBtn  = document.querySelector('.mobile-menu__close');
  if (!header) return;

  // Scroll class
  const onScroll = () => header.classList.toggle('is-scrolled', window.scrollY > 24);
  window.addEventListener('scroll', onScroll, { passive: true });
  onScroll();

  // Mobile menu open/close
  function openMenu() {
    mobileMenu?.classList.add('is-open');
    overlay?.classList.add('is-open');
    hamburger?.setAttribute('aria-expanded', 'true');
    document.body.style.overflow = 'hidden';
  }
  function closeMenu() {
    mobileMenu?.classList.remove('is-open');
    overlay?.classList.remove('is-open');
    hamburger?.setAttribute('aria-expanded', 'false');
    document.body.style.overflow = '';
  }

  hamburger?.addEventListener('click', () => {
    const isOpen = hamburger.getAttribute('aria-expanded') === 'true';
    isOpen ? closeMenu() : openMenu();
  });
  closeBtn?.addEventListener('click', closeMenu);
  overlay?.addEventListener('click', closeMenu);

  // Close on nav link click
  mobileMenu?.querySelectorAll('a').forEach(a => a.addEventListener('click', closeMenu));

  // Desktop services dropdown keyboard support
  const dropdownTrigger = document.querySelector('.header__dropdown-trigger');
  const dropdown        = document.getElementById('services-dropdown');
  if (dropdownTrigger && dropdown) {
    dropdownTrigger.addEventListener('click', () => {
      const expanded = dropdownTrigger.getAttribute('aria-expanded') === 'true';
      dropdownTrigger.setAttribute('aria-expanded', String(!expanded));
    });
    document.addEventListener('click', (e) => {
      if (!dropdownTrigger.parentElement?.contains(e.target)) {
        dropdownTrigger.setAttribute('aria-expanded', 'false');
      }
    });
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') dropdownTrigger.setAttribute('aria-expanded', 'false');
    });
  }

  // Active nav highlighting
  const path = window.location.pathname;
  document.querySelectorAll('.header__nav-link, .header__dropdown-link').forEach(link => {
    const href = link.getAttribute('href');
    if (href && (path === href || path === href + '/' || href !== '/' && path.startsWith(href))) {
      link.classList.add('is-active');
    }
  });
})();

/* ── Scroll-reveal ────────────────────────────────────────── */
(function initReveal() {
  const els = document.querySelectorAll(
    '.svc-card, .card, .value-card, .team-card, .process-step, .testimonial, [data-reveal]'
  );
  if (!els.length) return;

  const io = new IntersectionObserver((entries) => {
    entries.forEach((entry, i) => {
      if (entry.isIntersecting) {
        const el = entry.target;
        const delay = el.dataset.delay || (Array.from(el.parentElement?.children || []).indexOf(el) * 60);
        setTimeout(() => {
          el.style.opacity  = '1';
          el.style.transform = 'translateY(0)';
        }, Math.min(+delay, 400));
        io.unobserve(el);
      }
    });
  }, { threshold: 0.08, rootMargin: '0px 0px -40px 0px' });

  els.forEach((el) => {
    el.style.opacity   = '0';
    el.style.transform = 'translateY(24px)';
    el.style.transition = 'opacity 0.55s ease, transform 0.55s ease';
    io.observe(el);
  });
})();

/* ── Animated counters ────────────────────────────────────── */
(function initCounters() {
  const els = document.querySelectorAll('[data-count]');
  if (!els.length) return;

  const animate = (el) => {
    const target   = parseInt(el.dataset.count, 10);
    const suffix   = el.dataset.suffix || '';
    const duration = 1600;
    const start    = performance.now();
    const tick = (now) => {
      const t = Math.min((now - start) / duration, 1);
      const eased = 1 - Math.pow(1 - t, 3);
      el.textContent = Math.floor(eased * target) + suffix;
      if (t < 1) requestAnimationFrame(tick);
    };
    requestAnimationFrame(tick);
  };

  const io = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting) {
        animate(entry.target);
        io.unobserve(entry.target);
      }
    });
  }, { threshold: 0.5 });

  els.forEach(el => io.observe(el));
})();

/* ── Contact form ─────────────────────────────────────────── */
(function initForm() {
  const form = document.getElementById('contact-form');
  if (!form) return;

  form.addEventListener('submit', (e) => {
    e.preventDefault();
    const btn = form.querySelector('[type="submit"]');
    const orig = btn.innerHTML;
    btn.disabled = true;
    btn.innerHTML = '<span>Sending…</span>';

    // Swap in your form service (Formspree, Netlify, etc.) here
    setTimeout(() => {
      btn.innerHTML = '✓ Message Sent!';
      btn.style.background = '#3A7D5A';
      setTimeout(() => {
        btn.disabled = false;
        btn.innerHTML = orig;
        btn.style.background = '';
        form.reset();
      }, 3500);
    }, 1200);
  });
})();

